Here's an updated `BaseRepository` where you can find by a dynamic field:

```csharp
public abstract class BaseRepository<TEntity> : IBaseRepository<TEntity> where TEntity : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<TEntity> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<TEntity>();
    }

    public virtual TEntity GetById(int id)
    {
        return _dbSet.Find(id);
    }

    public virtual TEntity GetByDynamicField(string fieldName, object fieldValue)
    {
        // Use Expression to build a dynamic query
        var parameter = Expression.Parameter(typeof(TEntity));
        var property = Expression.Property(parameter, fieldName);
        var constant = Expression.Constant(fieldValue);
        var equal = Expression.Equal(property, constant);
        var lambda = Expression.Lambda<Func<TEntity, bool>>(equal, parameter);

        return _dbSet.FirstOrDefault(lambda);
    }

    // Other repository methods...
}
```

